1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PRICE = 60;
19	
20	const COMPONENT_TYPES = ["rune", "moonstone"];
21	
22	const isComponent = (item: { type: string }): boolean =>
23	  COMPONENT_TYPES.includes(item.type);
24	
25	const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM[item.type];
26	
27	export function quote(items: { type: string }[], context: QuoteContext): number {
28	  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
29	    const count = items.filter((item) => item.type === type).length;
30	    const groupPrice =
31	      count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];
32	    return sum + groupPrice;
33	  }, 0);
34	
35	  const mainBasePremium = items
36	    .filter((item) => !isComponent(item))
37	    .reduce((sum, item) => sum + basePremiumFor(item), 0);
38	
39	  return mainBasePremium + componentBasePremium + POLICY_FEE;
40	}
41	
42	export function claim(): unknown {
43	  return undefined;
44	}
